let aperto=!1;function soptis_toggleMenu(){aperto?(soptis_chiudiMenu(),aperto=!1):(soptis_apriMenu(),aperto=!0)}function soptis_apriMenu(){let e=document.querySelector("#header").getBoundingClientRect().height,t=document.querySelector("#mobile_menu");t.style.setProperty("--height-mobile-menu",`${e}px`),t.classList.remove("mobile_menu_close"),t.classList.add("mobile_menu_open");let i=document.querySelector("#mobile_button");i.innerHTML='<i class="fas fa-times fa-2x"></i>'}function soptis_chiudiMenu(){let e=document.querySelector("#mobile_menu");e.classList.remove("mobile_menu_open"),e.classList.add("mobile_menu_close");let t=document.querySelector("#mobile_button");t.innerHTML='<i class="fas fa-bars fa-2x"></i>'}